import pytest
from source import process_batch


def test_process_batch_includes_last_element():
    items = [1, 2, 3]
    result = process_batch(items)
    assert len(result) == len(items), (
        f"process_batch skipped the last element: expected {len(items)} results, got {len(result)}"
    )
    assert result[-1] == items[-1] * 2, (
        f"Last element should be {items[-1] * 2}, got {result[-1] if result else 'missing'}"
    )


def test_process_batch_single_element_not_empty():
    result = process_batch([5])
    assert result == [10], (
        f"Single-element list should return [10], got {result!r} (bug produces [])"
    )
